t.script:
(function() {
    var btnSearch = document.getElementById('btn_search_farmer');
    var searchFarmerId = document.getElementById('search_farmer_id');
    var searchNationalId = document.getElementById('search_national_id');
    var searchInlineStatus = document.getElementById('search_inline_status');
    var searchInlineStatusIcon = document.getElementById('search_inline_status_icon');
    var searchInlineStatusText = document.getElementById('search_inline_status_text');
    var resultsDiv = document.getElementById('farmer_search_results');
    var resultsList = document.getElementById('farmer_results_list');
    var createCard = document.getElementById('create_request_card');
    var formFarmerId = document.getElementById('form_farmer_id');
    var verificationRequiredNotice = document.getElementById('verification_required_notice');
    var consentFormFieldsWrapper = document.getElementById('consent_form_fields_wrapper');
    var selectedFarmerName = document.getElementById('selected_farmer_name');
    var selectedFarmerMeta = document.getElementById('selected_farmer_meta');
    var selectedFarmerImage = document.getElementById('selected_farmer_image');
    var selectedFarmerImagePlaceholder = document.getElementById('selected_farmer_image_placeholder');
    var btnClear = document.getElementById('btn_clear_farmer');
    var btnSubmitDisabledReason = document.getElementById('btn_submit_disabled_reason');
    var consentForm = document.getElementById('consent_request_form');
    var consentReasonInput = document.getElementById('consent_reason_id');
    var consentReasonError = document.getElementById('consent_reason_error');
    var dataFieldInputs = consentForm ? consentForm.querySelectorAll('input[name="allowed_data_field_ids"]') : [];
    var dataFieldsError = document.getElementById('data_fields_error');
    var attachmentInput = consentForm ? consentForm.querySelector('input[name="attachment"]') : null;
    var attachmentError = document.getElementById('attachment_error');
    var cameraDataInput = document.getElementById('camera_capture_data');
    var cameraTakenAtInput = document.getElementById('camera_capture_taken_at');
    var cameraLatitudeInput = document.getElementById('camera_capture_latitude');
    var cameraLongitudeInput = document.getElementById('camera_capture_longitude');
    var cameraAccuracyInput = document.getElementById('camera_capture_accuracy');
    var livenessChallengeIdInput = document.getElementById('liveness_challenge_id_input');
    var livenessVerificationTokenInput = document.getElementById('liveness_verification_token_input');
    var faydaOtpTransactionIdInput = document.getElementById('fayda_otp_transaction_id_input');
    var cameraInfo = document.getElementById('camera_capture_info');
    var cameraError = document.getElementById('camera_error');
    var cameraPreview = document.getElementById('camera_capture_preview');
    var cameraVideo = document.getElementById('camera_live_preview');
    var cameraCanvas = document.getElementById('camera_canvas');
    var faceMatchStatusText = document.getElementById('face_match_status_text');
    var faceMatchPercentText = document.getElementById('face_match_percent_text');
    var faceMatchReferencePreview = document.getElementById('face_match_reference_preview');
    var faceMatchReferenceEmpty = document.getElementById('face_match_reference_empty');
    var btnOpenCamera = document.getElementById('btn_open_camera');
    var btnTakeCameraPhoto = document.getElementById('btn_take_camera_photo');
    var btnCloseCamera = document.getElementById('btn_close_camera');
    var btnRetakeCameraPhoto = document.getElementById('btn_retake_camera_photo');
    var faydaOtpStatusText = document.getElementById('fayda_otp_status_text');
    var faydaOtpMetaText = document.getElementById('fayda_otp_meta_text');
    var otpVerificationChoiceHint = document.getElementById('otp_verification_choice_hint');
    var faceVerificationChoiceHint = document.getElementById('face_verification_choice_hint');
    var faydaOtpCodeInput = document.getElementById('fayda_otp_code');
    var btnRequestFaydaOtp = document.getElementById('btn_request_fayda_otp');
    var btnResendFaydaOtp = document.getElementById('btn_resend_fayda_otp');
    var btnVerifyFaydaOtp = document.getElementById('btn_verify_fayda_otp');
    var verificationSelector = document.getElementById('consent_verification_selector');
    var verificationOtpDetail = document.getElementById('consent_verification_otp_detail');
    var verificationFaceDetail = document.getElementById('consent_verification_face_detail');
    var btnSelectVerificationOtp = document.getElementById('btn_select_verification_otp');
    var btnSelectVerificationFace = document.getElementById('btn_select_verification_face');
    var btnChangeVerificationMethodFromOtp = document.getElementById('btn_change_verification_method_from_otp');
    var btnChangeVerificationMethodFromFace = document.getElementById('btn_change_verification_method_from_face');
    var tableWrap = document.getElementById('consent_table_wrap');
    var tableBody = document.getElementById('consent_request_table_body');
    var tableLoader = document.getElementById('consent_table_loader');
    var tableEnd = document.getElementById('consent_table_end');
    var reviewModalEl = document.getElementById('consent_review_modal');
    var notificationToggle = document.getElementById('consent_header_notification_toggle');
    var notificationMenu = document.getElementById('consent_header_notification_menu');
    var notificationCount = document.getElementById('consent_header_notification_count');
    var notificationList = document.getElementById('consent_header_notification_list');
    var notificationEmpty = document.getElementById('consent_header_notification_empty');
    var notificationMarkAll = document.getElementById('consent_header_notification_mark_all');
    var maxAttachmentSize = 10 * 1024 * 1024;
    var livenessChallengeTtlSeconds = 90;
    var faceApiScriptUrl = '/g2p_ati_consent_mgt/static/src/lib/face-api/face-api.js';
    var faceApiModelUrl = '/g2p_ati_consent_mgt/static/src/lib/face-api/model';
    var faceApiLoadPromise = null;
    var faceMatchDefaultThreshold = 0.45;
    var cameraStream = null;
    var selectedFarmer = null;
    var selectedVerificationMethod = '';
    var faceMatchSubmitPending = false;
    var faceMatchActionToken = 0;
    var faydaOtpActionToken = 0;
    var faceMatchState = {
        status: 'not_attempted',
        running: false,
        challengeId: '',
        nonce: '',
        promptSequence: [],
        expiresAt: '',
        verificationToken: '',
        distance: null,
        threshold: faceMatchDefaultThreshold
    };
    var faydaOtpState = {
        status: 'not_requested',
        running: false,
        transactionId: '',
        maskedMobile: ''
    };
    var searchState = {
        status: 'idle',
        query: '',
        farmer: null
    };

    function closeModalById(modalId) {
        if (!modalId) return;
        var modalEl = document.getElementById(modalId);
        if (!modalEl) return;
        if (window.bootstrap && window.bootstrap.Modal) {
            var modalInstance = window.bootstrap.Modal.getInstance(modalEl);
            if (modalInstance) {
                modalInstance.hide();
                return;
            }
        }
        if (window.jQuery && window.jQuery.fn && window.jQuery.fn.modal) {
            window.jQuery(modalEl).modal('hide');
        }
    }

    function initReviewModal() {
        if (!reviewModalEl) return;
        var closeUrl = reviewModalEl.getAttribute('data-close-url') || '/consent/management';
        var reviewModalRedirecting = false;

        function redirectToReviewList() {
            if (reviewModalRedirecting) return;
            reviewModalRedirecting = true;
            window.location.href = closeUrl;
        }

        if (reviewModalEl.parentElement !== document.body) {
            document.body.appendChild(reviewModalEl);
        }

        reviewModalEl.addEventListener('hidden.bs.modal', redirectToReviewList);

        if (window.bootstrap && window.bootstrap.Modal) {
            window.bootstrap.Modal.getOrCreateInstance(reviewModalEl).show();
        } else if (window.jQuery && window.jQuery.fn && window.jQuery.fn.modal) {
            window.jQuery(reviewModalEl).modal('show');
        } else {
            reviewModalEl.classList.add('show');
            reviewModalEl.style.display = 'block';
        }
    }
    var tableScrollTicking = false;
    var errorMessagesByCode = {
        access_denied: 'Access denied. Please contact your administrator.',
        missing_farmer: 'Please search and select a farmer first.',
        invalid_farmer: 'Invalid farmer selected.',
        farmer_not_found: 'Farmer not found.',
        missing_purpose: 'Consent reason is required.',
        missing_consent_reason: 'Consent reason is required.',
        invalid_consent_reason: 'Invalid consent reason selected.',
        missing_data_fields: 'No valid data fields selected. Configure partner data fields first.',
        missing_attachment: 'Attachment is required.',
        attachment_too_large: 'Attachment must be 10MB or smaller.',
        camera_too_large: 'Camera photo must be 10MB or smaller.',
        invalid_camera_data: 'Invalid camera image data.',
        invalid_camera_timestamp: 'Invalid camera timestamp.',
        invalid_camera_location: 'Invalid camera capture location.',
        server_error: 'An error occurred while creating the consent request.'
    };

    function toInt(value, fallbackValue) {
        var parsed = parseInt(value, 10);
        return Number.isFinite(parsed) ? parsed : fallbackValue;
    }

    var tableState = {
        total: toInt(tableWrap && tableWrap.getAttribute('data-total'), 0),
        limit: toInt(tableWrap && tableWrap.getAttribute('data-limit'), 10),
        offset: toInt(tableWrap && tableWrap.getAttribute('data-offset'), 0),
        loading: false,
        done: false
    };

    function formatDateForOdoo(dateObj) {
        function pad(v) { return String(v).padStart(2, '0'); }
        return dateObj.getFullYear() + '-' + pad(dateObj.getMonth() + 1) + '-' + pad(dateObj.getDate()) + ' ' +
            pad(dateObj.getHours()) + ':' + pad(dateObj.getMinutes()) + ':' + pad(dateObj.getSeconds());
    }

    function escapeAttr(value) {
        return htmlEscape(value).replace(/"/g, '&quot;');
    }

    function normalizeFaceMatchStatus(status) {
        return String(status || 'not_attempted').toLowerCase().replace(/[^a-z_]/g, '');
    }

    function formatLivenessPrompt(prompt) {
        return String(prompt || '')
            .split('_')
            .filter(function(part) { return !!part; })
            .map(function(part) {
                return part.charAt(0).toUpperCase() + part.slice(1);
            })
            .join(' ');
    }

    function updateFaceMatchPercentText() {
        if (!faceMatchPercentText) return;
        var prompts = Array.isArray(faceMatchState.promptSequence) ? faceMatchState.promptSequence : [];
        if (!prompts.length) {
            faceMatchPercentText.textContent = 'Challenge prompt and face score will appear here.';
            return;
        }
        var promptText = prompts.map(formatLivenessPrompt).join(' -> ');
        var expiresText = '';
        var faceScoreText = '';
        if (typeof faceMatchState.distance === 'number' && Number.isFinite(faceMatchState.distance)) {
            var similarityPct = Math.max(0, Math.min(100, (1 - faceMatchState.distance) * 100));
            var thresholdPct = Math.max(
                0,
                Math.min(100, (1 - (faceMatchState.threshold || faceMatchDefaultThreshold)) * 100)
            );
            faceScoreText = ' | Face: ' + similarityPct.toFixed(1) + '% (min ' + thresholdPct.toFixed(1) + '%)';
        }
        if (faceMatchState.expiresAt) {
            var expiresDate = new Date(faceMatchState.expiresAt.replace(' ', 'T') + 'Z');
            if (!Number.isNaN(expiresDate.getTime())) {
                expiresText = ' | Expires: ' + expiresDate.toLocaleTimeString();
            }
        }
        faceMatchPercentText.textContent = 'Challenge: ' + promptText + faceScoreText + expiresText;
    }

    function setPreviewImage(imgEl, emptyEl, imageUrl) {
        if (imgEl) {
            if (imageUrl) {
                imgEl.src = imageUrl;
                imgEl.classList.remove('d-none');
            } else {
                imgEl.removeAttribute('src');
                imgEl.classList.add('d-none');
            }
        }
        if (emptyEl) {
            emptyEl.classList.toggle('d-none', !!imageUrl);
        }
    }

    function isConsentVerificationComplete() {
        return faydaOtpState.status === 'verified' || faceMatchState.status === 'matched';
    }

    function updateConsentFormVisibility() {
        var isUnlocked = isConsentVerificationComplete();
        if (consentFormFieldsWrapper) {
            consentFormFieldsWrapper.classList.toggle('d-none', !isUnlocked);
            var fieldNodes = consentFormFieldsWrapper.querySelectorAll('input, select, textarea, button');
            for (var i = 0; i < fieldNodes.length; i++) {
                fieldNodes[i].disabled = !isUnlocked;
            }
        }
        if (verificationRequiredNotice) {
            verificationRequiredNotice.classList.toggle('is-success', isUnlocked);
            verificationRequiredNotice.textContent = isUnlocked
                ? 'Verification successful. You can now complete the consent request.'
                : 'Complete Fayda OTP or Face + Liveness verification to unlock the consent form.';
        }
    }

    function resetConsentFormInputs() {
        if (consentForm) {
            consentForm.reset();
        }
        if (formFarmerId) {
            formFarmerId.value = '';
        }
        setConsentReasonError('');
        setDataFieldsError('');
        setAttachmentError('');
        setCameraError('');
    }

    function resetFaceMatchFields() {
        if (livenessChallengeIdInput) livenessChallengeIdInput.value = '';
        if (livenessVerificationTokenInput) livenessVerificationTokenInput.value = '';
        faceMatchState.status = 'not_attempted';
        faceMatchState.running = false;
        faceMatchState.challengeId = '';
        faceMatchState.nonce = '';
        faceMatchState.promptSequence = [];
        faceMatchState.expiresAt = '';
        faceMatchState.verificationToken = '';
        faceMatchState.distance = null;
        faceMatchState.threshold = faceMatchDefaultThreshold;
        updateFaceMatchPercentText();
    }

    function setFaceMatchProcessing(message) {
        faceMatchState.status = 'processing';
        faceMatchState.running = true;
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-processing';
            faceMatchStatusText.textContent = message || 'Checking face + liveness...';
        }
        setFaceVerificationChoiceHint('processing', message || 'Checking face + liveness...');
        updateFaceMatchPercentText();
    }

    function setFaceVerificationChoiceHint(status, message) {
        if (!faceVerificationChoiceHint) return;
        var normalizedStatus = String(status || 'not_attempted').toLowerCase().replace(/[^a-z_]/g, '');
        var hintMessage = message || 'Not Attempted';
        var extraClass = '';

        if (normalizedStatus === 'processing') {
            hintMessage = 'Checking...';
            extraClass = 'is-processing';
        } else if (normalizedStatus === 'matched') {
            hintMessage = 'Verified';
            extraClass = 'is-success';
        } else if (normalizedStatus === 'error') {
            hintMessage = 'Try Again';
            extraClass = 'is-error';
        } else {
            hintMessage = 'Not Attempted';
        }

        faceVerificationChoiceHint.className = 'consent_verification_choice_text' + (extraClass ? ' ' + extraClass : '');
        faceVerificationChoiceHint.textContent = hintMessage;
    }

    function setFaceMatchResult(status, message, options) {
        var normalizedStatus = normalizeFaceMatchStatus(status);
        var opts = options || {};
        faceMatchState.status = normalizedStatus;
        faceMatchState.running = false;
        faceMatchState.challengeId = opts.challengeId || faceMatchState.challengeId || '';
        faceMatchState.nonce = opts.nonce || faceMatchState.nonce || '';
        faceMatchState.promptSequence = Array.isArray(opts.promptSequence)
            ? opts.promptSequence
            : (faceMatchState.promptSequence || []);
        faceMatchState.expiresAt = opts.expiresAt || faceMatchState.expiresAt || '';
        faceMatchState.verificationToken = opts.verificationToken || '';
        faceMatchState.distance = typeof opts.distance === 'number' && Number.isFinite(opts.distance)
            ? opts.distance
            : (typeof faceMatchState.distance === 'number' && Number.isFinite(faceMatchState.distance) ? faceMatchState.distance : null);
        faceMatchState.threshold = typeof opts.threshold === 'number' && Number.isFinite(opts.threshold)
            ? opts.threshold
            : (typeof faceMatchState.threshold === 'number' && Number.isFinite(faceMatchState.threshold) ? faceMatchState.threshold : faceMatchDefaultThreshold);

        if (livenessChallengeIdInput) {
            livenessChallengeIdInput.value = faceMatchState.challengeId || '';
        }
        if (livenessVerificationTokenInput) {
            livenessVerificationTokenInput.value =
                normalizedStatus === 'matched'
                    ? (faceMatchState.verificationToken || '')
                    : '';
        }
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-' + normalizedStatus.replace(/_/g, '-');
            faceMatchStatusText.textContent = message || '';
        }
        setFaceVerificationChoiceHint(normalizedStatus, message || 'Not Attempted');
        updateFaceMatchPercentText();
        updateConsentFormVisibility();
    }

    function resetFaceMatch(message) {
        resetFaceMatchFields();
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-not-attempted';
            faceMatchStatusText.textContent = message || 'Capture a photo to run face + liveness verification.';
        }
        setFaceVerificationChoiceHint('not_attempted', 'Not Attempted');
        updateFaceMatchPercentText();
        updateConsentFormVisibility();
    }

    function getFaydaOtpUnavailableReason(farmer) {
        if (!farmer) {
            return 'Select a farmer before requesting OTP.';
        }
        if (farmer.otp_available) {
            return '';
        }
        return 'OTP is unavailable for this farmer because the Fayda flow requires a Fayda identifier from the IDs tab. A primary phone can be used as the destination only when that identifier exists.';
    }

    function setOtpVerificationChoiceHint(status, options) {
        if (!otpVerificationChoiceHint) return;
        var normalizedStatus = String(status || 'not_requested').toLowerCase().replace(/[^a-z_]/g, '');
        var message = 'Not Attempted';
        var extraClass = '';

        if (!selectedFarmer) {
            message = 'Not Attempted';
        } else if (!selectedFarmer.otp_available) {
            message = 'Unavailable';
            extraClass = 'is-error';
        } else if (normalizedStatus === 'processing') {
            message = 'Checking...';
            extraClass = 'is-processing';
        } else if (normalizedStatus === 'requested') {
            message = 'Code Sent';
        } else if (normalizedStatus === 'verified') {
            message = 'Verified';
            extraClass = 'is-success';
        } else if (normalizedStatus === 'failed' || normalizedStatus === 'error') {
            message = 'Try Again';
            extraClass = 'is-error';
        } else {
            message = 'Not Attempted';
        }

        otpVerificationChoiceHint.className = 'consent_verification_choice_text' + (extraClass ? ' ' + extraClass : '');
        otpVerificationChoiceHint.textContent = message;
    }

    function setFaydaOtpButtonsState(inFlight, hasTransaction) {
        var otpAvailable = !!(selectedFarmer && selectedFarmer.otp_available);
        var unavailableReason = getFaydaOtpUnavailableReason(selectedFarmer);
        if (btnRequestFaydaOtp) {
            btnRequestFaydaOtp.disabled = !!inFlight || !otpAvailable;
            btnRequestFaydaOtp.title = !otpAvailable ? unavailableReason : '';
        }
        if (btnResendFaydaOtp) {
            btnResendFaydaOtp.disabled = !!inFlight || !otpAvailable;
            btnResendFaydaOtp.classList.toggle('d-none', !hasTransaction);
            btnResendFaydaOtp.title = !otpAvailable ? unavailableReason : '';
        }
        if (btnVerifyFaydaOtp) {
            btnVerifyFaydaOtp.disabled = !!inFlight || !hasTransaction;
            btnVerifyFaydaOtp.title = !hasTransaction && !otpAvailable ? unavailableReason : '';
        }
        if (faydaOtpCodeInput) faydaOtpCodeInput.disabled = !!inFlight || !hasTransaction;
    }

    function setFaydaOtpStatus(status, message, options) {
        var normalizedStatus = String(status || 'not_requested').toLowerCase().replace(/[^a-z_]/g, '');
        var opts = options || {};
        var transactionId = opts.transactionId || '';
        var maskedMobile = opts.maskedMobile || '';
        var identifierType = opts.identifierType || '';
        var identifierSource = opts.identifierSource || '';
        var verifiedAt = opts.verifiedAt || '';
        faydaOtpState.status = normalizedStatus;
        faydaOtpState.running = normalizedStatus === 'processing';
        faydaOtpState.transactionId = transactionId;
        faydaOtpState.maskedMobile = maskedMobile;
        if (faydaOtpTransactionIdInput) {
            faydaOtpTransactionIdInput.value = transactionId;
        }
        if (faydaOtpStatusText) {
            faydaOtpStatusText.className = 'consent_otp_status is-' + normalizedStatus.replace(/_/g, '-');
            faydaOtpStatusText.textContent = message || '';
        }
        if (faydaOtpMetaText) {
            var metaParts = [];
            if (maskedMobile) metaParts.push('Masked mobile: ' + maskedMobile);
            if (identifierType) metaParts.push('Identifier type: ' + identifierType);
            if (identifierSource) metaParts.push('Source: ' + identifierSource);
            if (verifiedAt) metaParts.push('Verified at: ' + verifiedAt);
            if (!metaParts.length) {
                metaParts.push('A verified OTP or successful face + liveness verification will auto-approve this request on submit.');
            }
            faydaOtpMetaText.textContent = metaParts.join(' | ');
        }
        setOtpVerificationChoiceHint(normalizedStatus, { maskedMobile: maskedMobile });
        setFaydaOtpButtonsState(normalizedStatus === 'processing', !!transactionId);
        updateConsentFormVisibility();
    }

    function resetFaydaOtp(message) {
        faydaOtpActionToken += 1;
        faydaOtpState.status = 'not_requested';
        faydaOtpState.running = false;
        faydaOtpState.transactionId = '';
        faydaOtpState.maskedMobile = '';
        if (faydaOtpTransactionIdInput) faydaOtpTransactionIdInput.value = '';
        if (faydaOtpCodeInput) {
            faydaOtpCodeInput.value = '';
            faydaOtpCodeInput.disabled = true;
        }
        if (faydaOtpStatusText) {
            faydaOtpStatusText.className = 'consent_otp_status is-not-requested';
            faydaOtpStatusText.textContent = message || 'Request OTP to verify the selected farmer.';
        }
        if (faydaOtpMetaText) {
            faydaOtpMetaText.textContent = 'A verified OTP or successful face + liveness verification will auto-approve this request on submit.';
        }
        setOtpVerificationChoiceHint('not_requested');
        setFaydaOtpButtonsState(false, false);
        updateConsentFormVisibility();
    }

    function getDefaultFaceMatchMessage(farmer, isRetake) {
        if (farmer) {
            return isRetake
                ? 'Retake the photo and complete face + liveness verification again.'
                : 'Capture a photo to run face + liveness verification.';
        }
        return 'Select a farmer, then capture a photo to run face + liveness verification.';
    }

    function getDefaultFaydaOtpMessage(farmer) {
        return farmer && farmer.otp_available
            ? 'Request OTP to verify the selected farmer.'
            : getFaydaOtpUnavailableReason(farmer);
    }

    function clearCameraCapture() {
        faceMatchActionToken += 1;
        stopCameraStream();
        if (cameraDataInput) cameraDataInput.value = '';
        if (cameraTakenAtInput) cameraTakenAtInput.value = '';
        clearCameraLocation();
        if (cameraPreview) {
            cameraPreview.src = '';
            cameraPreview.classList.add('d-none');
        }
        if (cameraVideo) {
            cameraVideo.classList.add('d-none');
        }
        if (cameraInfo) {
            cameraInfo.textContent = '';
            cameraInfo.classList.add('d-none');
        }
        setCameraError('');
        showCameraButtons(false, false);
    }

    function setVerificationMethod(method) {
        var normalizedMethod = method === 'otp' || method === 'face' ? method : '';
        var previousMethod = selectedVerificationMethod;

        if (previousMethod === 'face' && normalizedMethod !== 'face') {
            stopCameraStream();
            showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
        }

        selectedVerificationMethod = normalizedMethod;

        if (btnSelectVerificationOtp) {
            btnSelectVerificationOtp.classList.toggle('is-selected', normalizedMethod === 'otp');
        }
        if (btnSelectVerificationFace) {
            btnSelectVerificationFace.classList.toggle('is-selected', normalizedMethod === 'face');
        }

        if (normalizedMethod === 'otp') {
            var modalOtp = document.getElementById('modal_verification_otp');
            if (modalOtp) {
                if (window.bootstrap && window.bootstrap.Modal) {
                    window.bootstrap.Modal.getOrCreateInstance(modalOtp).show();
                } else if (window.jQuery) {
                    window.jQuery('#modal_verification_otp').modal('show');
                }
            }
        } else if (normalizedMethod === 'face') {
            var modalFace = document.getElementById('modal_verification_face');
            if (modalFace) {
                if (window.bootstrap && window.bootstrap.Modal) {
                    window.bootstrap.Modal.getOrCreateInstance(modalFace).show();
                } else if (window.jQuery) {
                    window.jQuery('#modal_verification_face').modal('show');
                }
            }
            requestLivenessChallenge();
        }
    }

    function callJsonRoute(url, params) {
        return new Promise(function(resolve, reject) {
            var req = new XMLHttpRequest();
            req.open('POST', url);
            req.setRequestHeader('Content-Type', 'application/json');
            req.setRequestHeader('Accept', 'application/json');
            req.onload = function() {
                var raw = {};
                try {
                    raw = JSON.parse(req.responseText || '{}');
                } catch (e) {
                    reject(new Error('Server returned an invalid response.'));
                    return;
                }
                var res = raw.result != null ? raw.result : raw;
                if (res && res.success) {
                    resolve(res);
                    return;
                }
                reject(new Error((res && res.message) || 'Request failed.'));
            };
            req.onerror = function() {
                reject(new Error('Network error while contacting the server.'));
            };
            req.send(JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: params || {},
                id: Date.now()
            }));
        });
    }

    function buildFarmerMeta(farmer) {
        if (!farmer) {
            return 'Farmer ID: —';
        }
        return 'Farmer ID: ' + (farmer.farmer_id || '—');
    }

    function setSearchButtonMode(mode) {
        if (!btnSearch) return;
        btnSearch.textContent = mode === 'select' ? 'Select' : 'Search';
    }

    function setSearchInlineState(status, text) {
        if (searchNationalId) {
            searchNationalId.classList.remove('is-found', 'is-missing', 'is-error');
        }
        if (searchInlineStatus) {
            searchInlineStatus.className = 'consent_search_inline_status';
        }
        if (searchInlineStatusIcon) {
            searchInlineStatusIcon.className = 'fa';
        }
        if (searchInlineStatusText) {
            searchInlineStatusText.textContent = '';
        }

        if (!status || status === 'idle') {
            return;
        }

        var iconClass = 'fa-info-circle';
        if (status === 'found') {
            iconClass = 'fa-check-circle';
        } else if (status === 'missing' || status === 'error') {
            iconClass = 'fa-times-circle';
        }

        if (searchNationalId) {
            searchNationalId.classList.add('is-' + status);
        }
        if (searchInlineStatus) {
            searchInlineStatus.classList.add('is-visible', 'is-' + status);
        }
        if (searchInlineStatusIcon) {
            searchInlineStatusIcon.classList.add(iconClass);
        }
        if (searchInlineStatusText) {
            searchInlineStatusText.textContent = text || '';
        }
    }

    function clearFarmerSearchResultState(options) {
        var opts = options || {};
        searchState.status = 'idle';
        searchState.query = '';
        searchState.farmer = null;
        setSearchInlineState('idle', '');
        setSearchButtonMode('search');
        if (resultsList) {
            resultsList.innerHTML = '';
        }
        if (resultsDiv) {
            resultsDiv.classList.add('d-none');
        }
        if (!opts.keepSelection) {
            applySelectedFarmer(null);
        }
    }

    function buildSearchFarmerPayload(farmer) {
        return {
            id: farmer.id,
            name: farmer.name || '',
            farmer_id: farmer.farmer_id || '',
            phone: farmer.phone || '',
            reg_ids: Array.isArray(farmer.reg_ids) ? farmer.reg_ids : [],
            profile_image_url: farmer.profile_image_url || '',
            otp_available: !!farmer.otp_available,
            otp_identifier_type: farmer.otp_identifier_type || '',
            otp_identifier_source: farmer.otp_identifier_source || ''
        };
    }

    function applySelectedFarmer(farmer) {
        resetConsentFormInputs();
        selectedFarmer = farmer || null;
        if (formFarmerId) {
            formFarmerId.value = farmer && farmer.id ? String(farmer.id) : '';
        }
        if (selectedFarmerName) {
            selectedFarmerName.textContent = farmer && farmer.name ? farmer.name : '—';
        }
        if (selectedFarmerMeta) {
            selectedFarmerMeta.textContent = buildFarmerMeta(farmer);
        }
        setPreviewImage(
            selectedFarmerImage,
            selectedFarmerImagePlaceholder,
            farmer && farmer.profile_image_url ? farmer.profile_image_url : ''
        );
        if (selectedFarmerImage) {
            selectedFarmerImage.alt = farmer && farmer.name
                ? farmer.name + ' photo'
                : 'Selected farmer photo';
        }
        setPreviewImage(
            faceMatchReferencePreview,
            faceMatchReferenceEmpty,
            farmer && farmer.profile_image_url ? farmer.profile_image_url : ''
        );
        createCard.classList.toggle('d-none', !farmer);
        if (resultsDiv) {
            if (farmer) {
                resultsDiv.classList.add('d-none');
            } else {
                resultsDiv.classList.toggle('d-none', !(resultsList && resultsList.innerHTML && resultsList.innerHTML.trim()));
            }
        }
        clearCameraCapture();
        setVerificationMethod('');
        resetFaceMatch(getDefaultFaceMatchMessage(farmer, false));
        resetFaydaOtp(getDefaultFaydaOtpMessage(farmer));
        updateConsentFormVisibility();
    }

    function parseOdooDate(value) {
        if (!value) return null;
        var normalized = String(value).replace(' ', 'T');
        var parsed = new Date(normalized + (normalized.endsWith('Z') ? '' : 'Z'));
        return Number.isNaN(parsed.getTime()) ? null : parsed;
    }

    function toFiniteNumber(value, fallback) {
        var parsed = Number(value);
        return Number.isFinite(parsed) ? parsed : fallback;
    }

    function loadImageForFaceMatch(src) {
        return new Promise(function(resolve, reject) {
            if (!src) {
                reject(new Error('Missing image source for face matching.'));
                return;
            }
            var img = new Image();
            img.onload = function() {
                resolve(img);
            };
            img.onerror = function() {
                reject(new Error('Unable to load image for face matching.'));
            };
            img.src = src;
        });
    }

    function ensureFaceApiReady() {
        if (window.faceapi && window.faceapi.nets && window.faceapi.nets.tinyFaceDetector && window.faceapi.nets.tinyFaceDetector.params) {
            return Promise.resolve(window.faceapi);
        }
        if (faceApiLoadPromise) {
            return faceApiLoadPromise;
        }
        faceApiLoadPromise = new Promise(function(resolve, reject) {
            function loadModels() {
                if (!window.faceapi || !window.faceapi.nets) {
                    reject(new Error('Face API library failed to initialize.'));
                    return;
                }
                Promise.all([
                    window.faceapi.nets.tinyFaceDetector.loadFromUri(faceApiModelUrl),
                    window.faceapi.nets.faceLandmark68Net.loadFromUri(faceApiModelUrl),
                    window.faceapi.nets.faceRecognitionNet.loadFromUri(faceApiModelUrl),
                ])
                    .then(function() {
                        resolve(window.faceapi);
                    })
                    .catch(function(err) {
                        reject(new Error(err && err.message ? err.message : 'Unable to load face recognition models.'));
                    });
            }

            if (window.faceapi) {
                loadModels();
                return;
            }

            var existingScript = document.querySelector('script[data-face-api-lib="1"]');
            if (existingScript) {
                existingScript.addEventListener('load', loadModels, { once: true });
                existingScript.addEventListener(
                    'error',
                    function() {
                        reject(new Error('Unable to load face recognition library.'));
                    },
                    { once: true }
                );
                return;
            }

            var script = document.createElement('script');
            script.src = faceApiScriptUrl;
            script.async = true;
            script.defer = true;
            script.setAttribute('data-face-api-lib', '1');
            script.onload = loadModels;
            script.onerror = function() {
                reject(new Error('Unable to load face recognition library.'));
            };
            document.head.appendChild(script);
        }).catch(function(err) {
            faceApiLoadPromise = null;
            throw err;
        });
        return faceApiLoadPromise;
    }

    function computeFaceDescriptorFromImage(imageEl) {
        if (!window.faceapi) {
            return Promise.resolve(null);
        }
        return window.faceapi
            .detectSingleFace(
                imageEl,
                new window.faceapi.TinyFaceDetectorOptions({ inputSize: 416, scoreThreshold: 0.4 })
            )
            .withFaceLandmarks()
            .withFaceDescriptor()
            .then(function(result) {
                if (!result || !result.descriptor) {
                    return null;
                }
                return result.descriptor;
            });
    }

    function runClientFaceMatch() {
        var referenceUrl = selectedFarmer && selectedFarmer.profile_image_url ? selectedFarmer.profile_image_url : '';
        if (!referenceUrl) {
            return Promise.resolve({
                passed: false,
                distance: null,
                threshold: faceMatchDefaultThreshold,
                message: 'Selected farmer has no profile image for face matching.',
            });
        }
        if (!cameraDataInput || !cameraDataInput.value) {
            return Promise.resolve({
                passed: false,
                distance: null,
                threshold: faceMatchDefaultThreshold,
                message: 'Capture a photo before running face match.',
            });
        }

        return ensureFaceApiReady()
            .then(function() {
                return Promise.all([
                    loadImageForFaceMatch(referenceUrl),
                    loadImageForFaceMatch(cameraDataInput.value),
                ]);
            })
            .then(function(images) {
                return Promise.all([
                    computeFaceDescriptorFromImage(images[0]),
                    computeFaceDescriptorFromImage(images[1]),
                ]);
            })
            .then(function(descriptors) {
                var referenceDescriptor = descriptors[0];
                var capturedDescriptor = descriptors[1];
                if (!referenceDescriptor) {
                    return {
                        passed: false,
                        distance: null,
                        threshold: faceMatchDefaultThreshold,
                        message: 'No face detected in the farmer profile image.',
                    };
                }
                if (!capturedDescriptor) {
                    return {
                        passed: false,
                        distance: null,
                        threshold: faceMatchDefaultThreshold,
                        message: 'No face detected in the captured image.',
                    };
                }
                var distance = window.faceapi.euclideanDistance(referenceDescriptor, capturedDescriptor);
                var threshold = faceMatchDefaultThreshold;
                var passed = Number.isFinite(distance) && distance <= threshold;
                if (!passed) {
                    return {
                        passed: false,
                        distance: Number.isFinite(distance) ? distance : null,
                        threshold: threshold,
                        message: 'Face match failed. Retake and align to the selected farmer.',
                    };
                }
                var similarityPct = Math.max(0, Math.min(100, (1 - distance) * 100));
                return {
                    passed: true,
                    distance: distance,
                    threshold: threshold,
                    message: 'Face match passed (' + similarityPct.toFixed(1) + '%).',
                };
            })
            .catch(function(error) {
                return {
                    passed: false,
                    distance: null,
                    threshold: faceMatchDefaultThreshold,
                    message: error && error.message ? error.message : 'Face matching failed.',
                };
            });
    }

    function requestLivenessChallenge() {
        var actionToken = ++faceMatchActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            resetFaceMatch('Select a farmer before requesting liveness challenge.');
            return Promise.resolve(false);
        }
        setFaceMatchProcessing('Requesting liveness challenge...');
        return callJsonRoute('/consent/liveness/request_challenge', {
            farmer_id: selectedFarmer.id
        }).then(function(res) {
            if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                return false;
            }
            var data = res.data || {};
            var ttlCandidate = Number(data.ttl_seconds || 0);
            if (Number.isFinite(ttlCandidate) && ttlCandidate > 0) {
                livenessChallengeTtlSeconds = ttlCandidate;
            }
            setFaceMatchResult(
                'not_attempted',
                'Challenge ready. Follow prompt and capture your photo.',
                {
                    challengeId: data.challenge_id || '',
                    nonce: data.nonce || '',
                    promptSequence: data.prompt_sequence || [],
                    expiresAt: data.expires_at || ''
                }
            );
            return data;
        }).catch(function(error) {
            if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                return false;
            }
            setFaceMatchResult(
                'error',
                error && error.message ? error.message : 'Unable to request liveness challenge.',
                {}
            );
            return false;
        });
    }

    function ensureLivenessChallenge() {
        var now = new Date();
        var expiresAt = parseOdooDate(faceMatchState.expiresAt);
        var hasValidChallenge = !!(
            faceMatchState.challengeId &&
            faceMatchState.nonce &&
            Array.isArray(faceMatchState.promptSequence) &&
            faceMatchState.promptSequence.length
        );
        if (!hasValidChallenge) {
            return requestLivenessChallenge();
        }
        if (expiresAt && now.getTime() >= expiresAt.getTime()) {
            return requestLivenessChallenge();
        }
        return Promise.resolve({
            challenge_id: faceMatchState.challengeId,
            nonce: faceMatchState.nonce,
            prompt_sequence: faceMatchState.promptSequence,
            expires_at: faceMatchState.expiresAt,
            ttl_seconds: livenessChallengeTtlSeconds
        });
    }

    function runFaceMatch() {
        var actionToken = ++faceMatchActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            resetFaceMatch('Select a farmer before capturing a photo.');
            return Promise.resolve(false);
        }
        if (!cameraDataInput || !cameraDataInput.value) {
            resetFaceMatch('Capture a photo before verifying liveness.');
            return Promise.resolve(false);
        }

        setFaceMatchProcessing('Preparing face + liveness checks...');
        return ensureLivenessChallenge().then(function(challengeData) {
            if (!challengeData) return false;
            if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                return false;
            }
            setFaceMatchProcessing('Running face match...');
            return runClientFaceMatch().then(function(faceMatchResult) {
                if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                    return false;
                }
                if (!faceMatchResult || !faceMatchResult.passed) {
                    setFaceMatchResult(
                        'error',
                        faceMatchResult && faceMatchResult.message
                            ? faceMatchResult.message
                            : 'Face match failed.',
                        {
                            challengeId: faceMatchState.challengeId || '',
                            nonce: faceMatchState.nonce || '',
                            promptSequence: faceMatchState.promptSequence || [],
                            expiresAt: faceMatchState.expiresAt || '',
                            distance: faceMatchResult ? faceMatchResult.distance : null,
                            threshold: faceMatchResult ? faceMatchResult.threshold : faceMatchDefaultThreshold,
                        }
                    );
                    return false;
                }
                setFaceMatchProcessing('Verifying liveness challenge...');
                return callJsonRoute('/consent/liveness/verify_challenge', {
                    farmer_id: selectedFarmer.id,
                    challenge_id: challengeData.challenge_id || faceMatchState.challengeId || '',
                    capture_image: cameraDataInput.value,
                    captured_at: cameraTakenAtInput ? (cameraTakenAtInput.value || '') : '',
                    face_match_passed: true,
                    face_match_distance: faceMatchResult.distance,
                    face_match_threshold: faceMatchResult.threshold
                }).then(function(res) {
                    if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                        return false;
                    }
                    var data = res.data || {};
                    setFaceMatchResult(
                        'matched',
                        res.message || 'Face + liveness verified successfully. The request will be automatically approved on submit.',
                        {
                            challengeId: data.challenge_id || faceMatchState.challengeId || '',
                            nonce: faceMatchState.nonce || '',
                            promptSequence: data.prompt_sequence || faceMatchState.promptSequence || [],
                            expiresAt: faceMatchState.expiresAt || '',
                            verificationToken: data.verification_token || '',
                            distance: toFiniteNumber(data.face_match_distance, faceMatchResult.distance),
                            threshold: toFiniteNumber(data.face_match_threshold, faceMatchResult.threshold)
                        }
                    );
                    closeModalById('modal_verification_face');
                    window.setTimeout(function() {
                        showServiceProviderModal('Face + liveness verified successfully. You can now complete the consent request.', false);
                    }, 250);
                    return true;
                }).catch(function(error) {
                    if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                        return false;
                    }
                    setFaceMatchResult(
                        'error',
                        error && error.message ? error.message : 'Face + liveness verification failed.',
                        {
                            challengeId: faceMatchState.challengeId || '',
                            nonce: faceMatchState.nonce || '',
                            promptSequence: faceMatchState.promptSequence || [],
                            expiresAt: faceMatchState.expiresAt || '',
                            distance: faceMatchResult.distance,
                            threshold: faceMatchResult.threshold
                        }
                    );
                    return false;
                });
            });
        });
    }

    function requestFaydaOtp() {
        var actionToken = ++faydaOtpActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            setFaydaOtpStatus('error', 'Select a farmer before requesting OTP.');
            return Promise.resolve(false);
        }
        if (!selectedFarmer.otp_available) {
            setFaydaOtpStatus('error', 'Selected farmer has no Fayda OTP identifier.');
            return Promise.resolve(false);
        }
        setFaydaOtpStatus(
            'processing',
            'Requesting OTP from Fayda...',
            {
                identifierType: selectedFarmer.otp_identifier_type || '',
                identifierSource: selectedFarmer.otp_identifier_source || ''
            }
        );
        return callJsonRoute('/consent/fayda/request_otp', {
            farmer_id: selectedFarmer.id
        }).then(function(res) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            var data = res.data || {};
            setFaydaOtpStatus(
                'requested',
                res.message || 'OTP sent successfully.',
                {
                    transactionId: data.transaction_id || '',
                    maskedMobile: data.masked_mobile || '',
                    identifierType: data.identifier_type || selectedFarmer.otp_identifier_type || '',
                    identifierSource: data.identifier_source || selectedFarmer.otp_identifier_source || ''
                }
            );
            if (faydaOtpCodeInput) {
                faydaOtpCodeInput.focus();
            }
            return true;
        }).catch(function(error) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            setFaydaOtpStatus(
                'error',
                error && error.message ? error.message : 'Unable to request OTP.',
                {
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || ''
                }
            );
            return false;
        });
    }

    function verifyFaydaOtp() {
        var actionToken = ++faydaOtpActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            setFaydaOtpStatus('error', 'Select a farmer before verifying OTP.');
            return Promise.resolve(false);
        }
        if (!faydaOtpState.transactionId) {
            setFaydaOtpStatus('error', 'Request OTP first.');
            return Promise.resolve(false);
        }
        var otpCode = faydaOtpCodeInput ? (faydaOtpCodeInput.value || '').trim() : '';
        if (!otpCode) {
            setFaydaOtpStatus('error', 'Enter the OTP code.');
            return Promise.resolve(false);
        }
        setFaydaOtpStatus(
            'processing',
            'Verifying OTP with Fayda...',
            {
                transactionId: faydaOtpState.transactionId,
                maskedMobile: faydaOtpState.maskedMobile,
                identifierType: selectedFarmer.otp_identifier_type || '',
                identifierSource: selectedFarmer.otp_identifier_source || ''
            }
        );
        return callJsonRoute('/consent/fayda/verify_otp', {
            farmer_id: selectedFarmer.id,
            transaction_id: faydaOtpState.transactionId,
            otp_code: otpCode
        }).then(function(res) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            var data = res.data || {};
            setFaydaOtpStatus(
                'verified',
                res.message || 'Fayda OTP verified successfully.',
                {
                    transactionId: data.transaction_id || faydaOtpState.transactionId,
                    maskedMobile: data.masked_mobile || faydaOtpState.maskedMobile,
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || '',
                    verifiedAt: data.verified_at || ''
                }
            );
            closeModalById('modal_verification_otp');
            window.setTimeout(function() {
                showServiceProviderModal('Fayda OTP verified successfully. You can now submit the request.', false);
            }, 250);
            return true;
        }).catch(function(error) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            setFaydaOtpStatus(
                'failed',
                error && error.message ? error.message : 'OTP verification failed.',
                {
                    transactionId: faydaOtpState.transactionId,
                    maskedMobile: faydaOtpState.maskedMobile,
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || ''
                }
            );
            return false;
        });
    }

    function setConsentReasonError(message) {
        if (!consentReasonError) return;
        if (message) {
            consentReasonError.textContent = message;
            consentReasonError.classList.remove('d-none');
        } else {
            consentReasonError.textContent = '';
            consentReasonError.classList.add('d-none');
        }
    }

    function setDataFieldsError(message) {
        if (!dataFieldsError) return;
        if (message) {
            dataFieldsError.textContent = message;
            dataFieldsError.classList.remove('d-none');
        } else {
            dataFieldsError.textContent = '';
            dataFieldsError.classList.add('d-none');
        }
    }

    function setAttachmentError(message) {
        if (!attachmentError) return;
        if (message) {
            attachmentError.textContent = message;
            attachmentError.classList.remove('d-none');
        } else {
            attachmentError.textContent = '';
            attachmentError.classList.add('d-none');
        }
    }

    function setCameraError(message) {
        if (!cameraError) return;
        if (message) {
            cameraError.textContent = message;
            cameraError.classList.remove('d-none');
        } else {
            cameraError.textContent = '';
            cameraError.classList.add('d-none');
        }
    }

    function showServiceProviderModal(message, isError) {
        var modalEl = document.getElementById('successModal');
        if (!modalEl || !message) return;
        var imgEl = modalEl.querySelector('.popup_img');
        var titleEl = modalEl.querySelector('h4');
        var msgEl = modalEl.querySelector('.popup_msg');
        if (imgEl) {
            imgEl.src = isError
                ? '/g2p_ati_service_provider_portal/static/src/img/no.png'
                : '/g2p_ati_service_provider_portal/static/src/img/ok.png';
        }
        if (titleEl) {
            titleEl.textContent = isError ? 'Error' : 'Success!';
        }
        if (msgEl) {
            msgEl.textContent = message;
        }
        if (window.jQuery && window.jQuery.fn && window.jQuery.fn.modal) {
            window.jQuery('#successModal').modal('show');
        } else if (window.bootstrap && window.bootstrap.Modal) {
            window.bootstrap.Modal.getOrCreateInstance(modalEl).show();
        }
    }

    function setNotificationMenuOpen(isOpen) {
        if (!notificationMenu || !notificationToggle) return;
        notificationMenu.classList.toggle('is-open', !!isOpen);
        notificationToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    }

    function updateNotificationCount() {
        if (!notificationCount) return Promise.resolve(0);
        return fetch('/get_notification_count', {
            method: 'GET',
            headers: { 'Content-Type': 'application/json' }
        }).then(function(response) {
            return response.json();
        }).then(function(data) {
            var count = 0;
            if (Array.isArray(data) && data.length) {
                count = parseInt(data[0].count || 0, 10) || 0;
            }
            notificationCount.textContent = String(count);
            notificationCount.classList.toggle('d-none', count <= 0);
            return count;
        }).catch(function() {
            notificationCount.textContent = '0';
            notificationCount.classList.add('d-none');
            return 0;
        });
    }

    function renderNotifications(notifications) {
        if (!notificationList || !notificationEmpty) return;
        notificationList.innerHTML = '';
        var rows = Array.isArray(notifications) ? notifications : [];
        if (!rows.length) {
            notificationEmpty.textContent = 'No new notifications.';
            notificationEmpty.classList.remove('d-none');
            return;
        }

        notificationEmpty.classList.add('d-none');
        rows.forEach(function(notification) {
            var item = document.createElement('div');
            item.className = 'consent_portal_notification_item';

            var link = document.createElement('a');
            link.className = 'consent_portal_notification_link';
            link.href = notification && notification.url ? notification.url : '/serviceprovider/update/suggests';
            link.textContent = notification && notification.message ? notification.message : 'Open notification';
            link.addEventListener('click', function(e) {
                var targetUrl = link.href;
                e.preventDefault();
                Promise.resolve(
                    fetch('/mark_notification_seen', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ notification_id: notification && notification.id ? notification.id : null })
                    }).catch(function() {
                        return null;
                    })
                ).finally(function() {
                    updateNotificationCount();
                    setNotificationMenuOpen(false);
                    window.location.href = targetUrl;
                });
            });

            item.appendChild(link);
            notificationList.appendChild(item);
        });
    }

    function loadNotifications() {
        if (!notificationList || !notificationEmpty) return Promise.resolve([]);
        notificationList.innerHTML = '';
        notificationEmpty.textContent = 'Loading notifications...';
        notificationEmpty.classList.remove('d-none');
        return fetch('/get_notifications', {
            method: 'GET',
            headers: { 'Content-Type': 'application/json' }
        }).then(function(response) {
            return response.json();
        }).then(function(data) {
            renderNotifications(data);
            return data;
        }).catch(function() {
            notificationList.innerHTML = '';
            notificationEmpty.textContent = 'Unable to load notifications.';
            notificationEmpty.classList.remove('d-none');
            return [];
        });
    }

    function hasSelectedDataField() {
        if (!dataFieldInputs || !dataFieldInputs.length) return false;
        for (var i = 0; i < dataFieldInputs.length; i++) {
            if (dataFieldInputs[i].checked) return true;
        }
        return false;
    }

    function stopCameraStream() {
        if (!cameraStream) return;
        var tracks = cameraStream.getTracks ? cameraStream.getTracks() : [];
        for (var i = 0; i < tracks.length; i++) {
            tracks[i].stop();
        }
        cameraStream = null;
        if (cameraVideo) {
            cameraVideo.pause();
            cameraVideo.srcObject = null;
        }
    }

    function showCameraButtons(isLive, hasCapture) {
        if (btnTakeCameraPhoto) btnTakeCameraPhoto.classList.toggle('d-none', !isLive);
        if (btnCloseCamera) btnCloseCamera.classList.toggle('d-none', !isLive);
        if (btnRetakeCameraPhoto) btnRetakeCameraPhoto.classList.toggle('d-none', isLive || !hasCapture);
    }

    function clearCameraLocation() {
        if (cameraLatitudeInput) cameraLatitudeInput.value = '';
        if (cameraLongitudeInput) cameraLongitudeInput.value = '';
        if (cameraAccuracyInput) cameraAccuracyInput.value = '';
    }

    function getCameraLocation(callback) {
        if (!navigator.geolocation) {
            clearCameraLocation();
            callback(false);
            return;
        }
        navigator.geolocation.getCurrentPosition(
            function(position) {
                if (cameraLatitudeInput) cameraLatitudeInput.value = String(position.coords.latitude);
                if (cameraLongitudeInput) cameraLongitudeInput.value = String(position.coords.longitude);
                if (cameraAccuracyInput) cameraAccuracyInput.value = String(position.coords.accuracy || '');
                callback(true);
            },
            function() {
                clearCameraLocation();
                callback(false);
            },
            {
                enableHighAccuracy: true,
                timeout: 8000,
                maximumAge: 0
            }
        );
    }

    function htmlEscape(value) {
        return String(value == null ? '' : value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function normalizeStatus(status) {
        return String(status || '').toLowerCase().replace(/[^a-z0-9_-]/g, '');
    }

    function statusIcon(status) {
        var normalized = normalizeStatus(status);
        if (normalized === 'approved') return '&#10003;';
        if (normalized === 'pending') return '&#128336;';
        if (normalized === 'rejected' || normalized === 'denied') return '&#10005;';
        if (normalized === 'expired' || normalized === 'revoked') return '&#128336;';
        return '';
    }

    function buildTableRowHtml(row) {
        var requestId = htmlEscape(row.consent_creation_request_id || row.request_id || '');
        var farmerName = htmlEscape(row.farmer_name || '');
        var consentType = htmlEscape(row.consent_type || '');
        var createdAt = htmlEscape(row.created_at || '');
        var statusValue = row.status || '';
        var normalizedStatus = normalizeStatus(statusValue);
        var statusText = htmlEscape(statusValue || '');
        var statusHtml = '<span class="consent_status_badge consent_status_' + normalizedStatus + '">' + statusIcon(statusValue) + statusText + '</span>';
        var reviewUrl = row.review_url || ('/consent/management/review/' + String(row.id || '') + '?view=table');
        var reviewHref = htmlEscape(reviewUrl);
        return '<tr class="consent_request_row consent_request_row--' + normalizedStatus + '">' +
            '<td class="consent_table_id">' + (requestId || '-') + '</td>' +
            '<td><span class="fw-semibold consent_farmer_name consent_table_farmer_name">' + farmerName + '</span></td>' +
            '<td><span class="consent_table_type_chip">' + consentType + '</span></td>' +
            '<td>' + statusHtml + '</td>' +
            '<td class="consent_table_date">' + createdAt + '</td>' +
            '<td class="consent_table_action"><a href="' + reviewHref + '" class="btn btn-sm consent_request_card_btn"><i class="fa fa-eye" aria-hidden="true"></i>View Details</a></td>' +
            '</tr>';
    }

    function setTableLoaderVisible(isVisible) {
        if (!tableLoader) return;
        tableLoader.classList.toggle('d-none', !isVisible);
    }

    function setTableEndVisible(isVisible) {
        if (!tableEnd) return;
        tableEnd.classList.toggle('d-none', !isVisible);
    }

    function shouldFetchTableRows() {
        if (!tableWrap || !tableBody || tableState.loading || tableState.done) return false;
        var viewportHeight = window.innerHeight || document.documentElement.clientHeight || 0;
        var rect = tableWrap.getBoundingClientRect();
        return rect.bottom <= viewportHeight + 180;
    }

    function fetchTableRows(offset, limit, done) {
        var req = new XMLHttpRequest();
        req.open('POST', '/consent/management/table_fetch');
        req.setRequestHeader('Content-Type', 'application/json');
        req.setRequestHeader('Accept', 'application/json');
        req.onload = function() {
            var raw = {};
            try { raw = JSON.parse(req.responseText || '{}'); } catch (e) {}
            var res = raw.result != null ? raw.result : raw;
            if (req.status >= 200 && req.status < 300 && res && res.success && res.data) {
                done(null, res.data);
                return;
            }
            done(new Error('Unable to fetch more consent requests.'));
        };
        req.onerror = function() {
            done(new Error('Network error while fetching consent requests.'));
        };
        req.send(JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: { offset: offset, limit: limit },
            id: Date.now()
        }));
    }

    function markTableDone() {
        tableState.done = true;
        setTableLoaderVisible(false);
        setTableEndVisible(true);
    }

    function loadMoreTableRows() {
        if (!tableWrap || !tableBody || tableState.loading || tableState.done) return;
        if (tableState.total > 0 && tableState.offset >= tableState.total) {
            markTableDone();
            return;
        }

        tableState.loading = true;
        setTableLoaderVisible(true);
        setTableEndVisible(false);

        fetchTableRows(tableState.offset, tableState.limit, function(error, data) {
            tableState.loading = false;
            setTableLoaderVisible(false);

            if (error || !data) {
                return;
            }

            tableState.total = toInt(data.total, tableState.total);
            var rows = Array.isArray(data.rows) ? data.rows : [];
            for (var i = 0; i < rows.length; i++) {
                tableBody.insertAdjacentHTML('beforeend', buildTableRowHtml(rows[i]));
            }
            tableState.offset += rows.length;
            if (tableWrap) {
                tableWrap.setAttribute('data-offset', String(tableState.offset));
            }

            if (!rows.length || (tableState.total > 0 && tableState.offset >= tableState.total)) {
                markTableDone();
                return;
            }

            if (shouldFetchTableRows()) {
                loadMoreTableRows();
            }
        });
    }

    function onTableScroll() {
        if (tableScrollTicking) return;
        tableScrollTicking = true;
        window.requestAnimationFrame(function() {
            tableScrollTicking = false;
            if (shouldFetchTableRows()) {
                loadMoreTableRows();
            }
        });
    }

    function initInfiniteTable() {
        if (!tableWrap || !tableBody) return;
        tableState.limit = Math.max(1, tableState.limit);
        if (tableState.total > 0 && tableState.offset >= tableState.total) {
            markTableDone();
            return;
        }
        window.addEventListener('scroll', onTableScroll, { passive: true });
        window.addEventListener('resize', onTableScroll);
        onTableScroll();
    }

    function searchFarmers() {
        var singleQuery = (searchNationalId && searchNationalId.value) ? searchNationalId.value.trim() : '';

        if (searchState.status === 'found' && searchState.farmer && searchState.query === singleQuery) {
            applySelectedFarmer(searchState.farmer);
            return;
        }

        applySelectedFarmer(null);
        if (resultsList) {
            resultsList.innerHTML = '';
        }
        if (resultsDiv) {
            resultsDiv.classList.add('d-none');
        }
        if (!singleQuery) {
            clearFarmerSearchResultState({ keepSelection: true });
            return;
        }
        callJsonRoute('/consent/search_farmer', { query: singleQuery })
            .then(function(res) {
            if (res.success && res.data && res.data.farmers && res.data.farmers.length) {
                searchState.status = 'found';
                searchState.query = singleQuery;
                searchState.farmer = buildSearchFarmerPayload(res.data.farmers[0]);
                setSearchInlineState('found', 'Found');
                setSearchButtonMode('select');
            } else {
                searchState.status = 'missing';
                searchState.query = singleQuery;
                searchState.farmer = null;
                setSearchInlineState('missing', 'Not Found');
                setSearchButtonMode('search');
            }
            })
            .catch(function(error) {
                searchState.status = 'error';
                searchState.query = singleQuery;
                searchState.farmer = null;
                setSearchInlineState('error', 'Search Failed');
                setSearchButtonMode('search');
            });
    }

    if (btnSearch) btnSearch.addEventListener('click', searchFarmers);
    if (searchNationalId) searchNationalId.addEventListener('keydown', function(e) { if (e.key === 'Enter') { e.preventDefault(); searchFarmers(); } });
    if (searchNationalId) {
        searchNationalId.addEventListener('input', function() {
            clearFarmerSearchResultState();
        });
    }
    if (notificationToggle) {
        notificationToggle.addEventListener('click', function(e) {
            e.preventDefault();
            var willOpen = !(notificationMenu && notificationMenu.classList.contains('is-open'));
            setNotificationMenuOpen(willOpen);
            if (willOpen) {
                loadNotifications();
            }
        });
        updateNotificationCount();
    }
    if (notificationMarkAll) {
        notificationMarkAll.addEventListener('click', function(e) {
            e.preventDefault();
            fetch('/view_all_notifications', { method: 'GET' })
                .catch(function() { return null; })
                .finally(function() {
                    updateNotificationCount();
                    setNotificationMenuOpen(false);
                    window.location.href = '/serviceprovider/update/suggests';
                });
        });
    }
    document.addEventListener('click', function(e) {
        if (!notificationToggle || !notificationMenu) return;
        if (notificationToggle.contains(e.target) || notificationMenu.contains(e.target)) return;
        setNotificationMenuOpen(false);
    });
    if (btnSelectVerificationOtp) {
        btnSelectVerificationOtp.addEventListener('click', function() {
            setVerificationMethod('otp');
        });
    }
    if (btnSelectVerificationFace) {
        btnSelectVerificationFace.addEventListener('click', function() {
            setVerificationMethod('face');
        });
    }
    var modalOtpEl = document.getElementById('modal_verification_otp');
    if (modalOtpEl) {
        document.body.appendChild(modalOtpEl);
        modalOtpEl.addEventListener('hidden.bs.modal', function() {
            if (selectedVerificationMethod === 'otp') {
                setVerificationMethod('');
            }
        });
        if (window.jQuery) {
            window.jQuery(modalOtpEl).on('hidden.bs.modal', function() {
                if (selectedVerificationMethod === 'otp') {
                    setVerificationMethod('');
                }
            });
        }
    }
    var modalFaceEl = document.getElementById('modal_verification_face');
    if (modalFaceEl) {
        document.body.appendChild(modalFaceEl);
        modalFaceEl.addEventListener('hidden.bs.modal', function() {
            if (selectedVerificationMethod === 'face') {
                setVerificationMethod('');
            }
            stopCameraStream();
            showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
        });
        if (window.jQuery) {
            window.jQuery(modalFaceEl).on('hidden.bs.modal', function() {
                if (selectedVerificationMethod === 'face') {
                    setVerificationMethod('');
                }
                stopCameraStream();
                showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
            });
        }
    }
    if (btnRequestFaydaOtp) {
        btnRequestFaydaOtp.addEventListener('click', function() {
            requestFaydaOtp();
        });
    }
    if (btnResendFaydaOtp) {
        btnResendFaydaOtp.addEventListener('click', function() {
            requestFaydaOtp();
        });
    }
    if (btnVerifyFaydaOtp) {
        btnVerifyFaydaOtp.addEventListener('click', function() {
            verifyFaydaOtp();
        });
    }
    if (faydaOtpCodeInput) {
        faydaOtpCodeInput.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') {
                e.preventDefault();
                verifyFaydaOtp();
            }
        });
    }
    if (btnClear) {
        btnClear.addEventListener('click', function() {
            applySelectedFarmer(null);
        });
    }
    if (btnSubmitDisabledReason) {
        btnSubmitDisabledReason.addEventListener('click', function() {
            var msg = 'No data fields are configured for your consent partner. Contact admin.';
            setDataFieldsError(msg);
            showServiceProviderModal(msg, true);
            console.warn('Consent portal submit blocked on client: no partner data fields configured.');
        });
    }
    if (attachmentInput) {
        attachmentInput.addEventListener('change', function() {
            setAttachmentError('');
            var file = (this.files && this.files.length) ? this.files[0] : null;
            if (file && file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
            }
        });
    }
    if (consentReasonInput) {
        consentReasonInput.addEventListener('change', function() {
            if ((this.value || '').trim()) {
                setConsentReasonError('');
            }
        });
    }
    if (dataFieldInputs && dataFieldInputs.length) {
        for (var i = 0; i < dataFieldInputs.length; i++) {
            dataFieldInputs[i].addEventListener('change', function() {
                if (hasSelectedDataField()) {
                    setDataFieldsError('');
                }
            });
        }
    }
    if (btnOpenCamera) {
        btnOpenCamera.addEventListener('click', function() {
            setCameraError('');
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                setCameraError('Camera is not supported on this device/browser.');
                return;
            }
            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } })
                .then(function(stream) {
                    cameraStream = stream;
                    if (cameraVideo) {
                        cameraVideo.srcObject = stream;
                        cameraVideo.classList.remove('d-none');
                    }
                    showCameraButtons(true, false);
                })
                .catch(function() {
                    setCameraError('Unable to access camera. Please allow camera permission.');
                });
        });
    }

    if (btnCloseCamera) {
        btnCloseCamera.addEventListener('click', function() {
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
        });
    }

    if (btnTakeCameraPhoto) {
        btnTakeCameraPhoto.addEventListener('click', function() {
            setCameraError('');
            if (!cameraVideo || !cameraCanvas || !cameraStream) {
                setCameraError('Open camera first.');
                return;
            }
            var width = cameraVideo.videoWidth || 0;
            var height = cameraVideo.videoHeight || 0;
            if (!width || !height) {
                setCameraError('Camera preview not ready. Try again.');
                return;
            }
            cameraCanvas.width = width;
            cameraCanvas.height = height;
            var ctx = cameraCanvas.getContext('2d');
            ctx.drawImage(cameraVideo, 0, 0, width, height);
            var dataUrl = cameraCanvas.toDataURL('image/jpeg', 0.9);
            var base64Part = dataUrl.split(',')[1] || '';
            var approxBytes = Math.floor((base64Part.length * 3) / 4);
            if (approxBytes > maxAttachmentSize) {
                setCameraError('Camera photo must be 10MB or smaller.');
                return;
            }
            if (cameraDataInput) cameraDataInput.value = dataUrl;
            var capturedAt = new Date();
            if (cameraTakenAtInput) cameraTakenAtInput.value = formatDateForOdoo(capturedAt);
            clearCameraLocation();
            if (cameraInfo) {
                cameraInfo.textContent = 'Captured at: ' + capturedAt.toLocaleString() + ' (getting location...)';
                cameraInfo.classList.remove('d-none');
            }
            getCameraLocation(function(hasLocation) {
                if (!cameraInfo) return;
                var message = 'Captured at: ' + capturedAt.toLocaleString();
                if (hasLocation && cameraLatitudeInput && cameraLongitudeInput) {
                    var lat = Number(cameraLatitudeInput.value || 0).toFixed(6);
                    var lon = Number(cameraLongitudeInput.value || 0).toFixed(6);
                    message += ' | Location: ' + lat + ', ' + lon;
                    if (cameraAccuracyInput && cameraAccuracyInput.value) {
                        var accuracy = Number(cameraAccuracyInput.value || 0).toFixed(1);
                        message += ' (± ' + accuracy + ' m)';
                    }
                } else {
                    message += ' | Location unavailable';
                }
                cameraInfo.textContent = message;
                cameraInfo.classList.remove('d-none');
            });
            if (cameraPreview) {
                cameraPreview.src = dataUrl;
                cameraPreview.classList.remove('d-none');
            }
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, true);
            runFaceMatch();
        });
    }

    if (btnRetakeCameraPhoto) {
        btnRetakeCameraPhoto.addEventListener('click', function() {
            clearCameraCapture();
            resetFaceMatch(getDefaultFaceMatchMessage(selectedFarmer, true));
            if (selectedFarmer && selectedFarmer.id && selectedVerificationMethod === 'face') {
                requestLivenessChallenge();
            }
        });
    }
    if (consentForm) {
        consentForm.addEventListener('submit', function(e) {
            var hasError = false;
            var firstErrorMessage = '';
            var shouldAttemptFaceMatch = !!(
                selectedVerificationMethod === 'face' &&
                selectedFarmer &&
                cameraDataInput &&
                cameraDataInput.value &&
                faydaOtpState.status !== 'verified'
            );
            setConsentReasonError('');
            setDataFieldsError('');
            setAttachmentError('');
            setCameraError('');

            if (!selectedFarmer || !formFarmerId || !formFarmerId.value) {
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Please search and select a farmer first.';
            }
            if (!isConsentVerificationComplete()) {
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Complete Fayda OTP or Face + Liveness verification before continuing.';
            }
            if (!consentReasonInput || !(consentReasonInput.value || '').trim()) {
                setConsentReasonError('Consent reason is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Consent reason is required.';
            }
            if (dataFieldInputs && dataFieldInputs.length && !hasSelectedDataField()) {
                setDataFieldsError('Select at least one data field.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Select at least one data field.';
            }
            if (!attachmentInput) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            }
            var file = attachmentInput && attachmentInput.files && attachmentInput.files.length ? attachmentInput.files[0] : null;
            if (!file) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            } else if (file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment must be 10MB or smaller.';
            }

            if (cameraDataInput && cameraDataInput.value) {
                var rawBase64 = cameraDataInput.value.split(',')[1] || '';
                var approxBytes = Math.floor((rawBase64.length * 3) / 4);
                if (approxBytes > maxAttachmentSize) {
                    setCameraError('Camera photo must be 10MB or smaller.');
                    hasError = true;
                    if (!firstErrorMessage) firstErrorMessage = 'Camera photo must be 10MB or smaller.';
                }
            }

            if (faceMatchState.running) {
                setCameraError('Face + liveness verification is still running. Please wait a moment.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Face + liveness verification is still running. Please wait a moment.';
            }
            if (faydaOtpState.running) {
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'OTP verification is still running. Please wait a moment.';
            }

            if (hasError) {
                console.warn('Consent portal submit blocked on client validation.', {
                    hasReason: !!(consentReasonInput && (consentReasonInput.value || '').trim()),
                    hasSelectedDataField: hasSelectedDataField(),
                    hasAttachment: !!(attachmentInput && attachmentInput.files && attachmentInput.files.length),
                    dataFieldInputsCount: dataFieldInputs ? dataFieldInputs.length : 0
                });
                showServiceProviderModal(firstErrorMessage || 'Please fix form validation errors.', true);
                e.preventDefault();
            } else if (shouldAttemptFaceMatch && !faceMatchSubmitPending && faceMatchState.status !== 'matched') {
                e.preventDefault();
                faceMatchSubmitPending = true;
                setCameraError('');
                setFaceMatchProcessing('Verifying face + liveness before submit...');
                runFaceMatch().finally(function() {
                    faceMatchSubmitPending = false;
                    if (typeof consentForm.requestSubmit === 'function') {
                        consentForm.requestSubmit();
                    } else {
                        consentForm.submit();
                    }
                });
            } else {
                console.info('Consent portal submit passed client validation. Submitting form.');
            }
        });
    }

    setVerificationMethod('');
    resetFaceMatch(getDefaultFaceMatchMessage(null, false));
    resetFaydaOtp(getDefaultFaydaOtpMessage(null));
    updateConsentFormVisibility();

    (function showServerErrorPopup() {
        var errorCode = '';
        try {
            errorCode = new URLSearchParams(window.location.search).get('error') || '';
        } catch (e) {
            errorCode = '';
        }
        if (!errorCode) return;
        var message = errorMessagesByCode[errorCode];
        if (!message) return;
        showServiceProviderModal(message, true);
    })();
    (function initPortalSectionTabs() {
        var managementTabLink = document.getElementById('portal_management_tab_link');
        var workspaceTabLink = document.getElementById('consent_workspace_tab_link');
        if (!managementTabLink || !workspaceTabLink || !window.bootstrap || !window.bootstrap.Tab) {
            return;
        }

        function showTabFromHash() {
            if (window.location.hash === '#portal_management') {
                window.bootstrap.Tab.getOrCreateInstance(managementTabLink).show();
                return;
            }
            if (window.location.hash === '#consent_workspace') {
                window.bootstrap.Tab.getOrCreateInstance(workspaceTabLink).show();
            }
        }

        managementTabLink.addEventListener('shown.bs.tab', function() {
            if (window.location.hash !== '#portal_management') {
                window.history.replaceState(null, '', '#portal_management');
            }
        });
        workspaceTabLink.addEventListener('shown.bs.tab', function() {
            if (window.location.hash === '#portal_management') {
                window.history.replaceState(
                    null,
                    '',
                    window.location.pathname + window.location.search + '#consent_workspace'
                );
            }
        });

        window.addEventListener('hashchange', showTabFromHash);
        showTabFromHash();
    })();
    initReviewModal();
    window.addEventListener('beforeunload', function() {
        stopCameraStream();
    });
})();
